3130 void llvm::copyMetadataForLoad(LoadInst &Dest, const LoadInst &Source) {
3131   SmallVector<std::pair<unsigned, MDNode *>, 8> MD;
3132   Source.getAllMetadata(MD);
3133   MDBuilder MDB(Dest.getContext());
3134   Type *NewType = Dest.getType();
3135   const DataLayout &DL = Source.getDataLayout();
3136   for (const auto &MDPair : MD) {
3137     unsigned ID = MDPair.first;
3138     MDNode *N = MDPair.second;
3139     // Note, essentially every kind of metadata should be preserved here! This
3140     // routine is supposed to clone a load instruction changing *only its type*.
3141     // The only metadata it makes sense to drop is metadata which is invalidated
3142     // when the pointer type changes. This should essentially never be the case
3143     // in LLVM, but we explicitly switch over only known metadata to be
3144     // conservatively correct. If you are adding metadata to LLVM which pertains
3145     // to loads, you almost certainly want to add it here.
3146     switch (ID) {
3147     case LLVMContext::MD_dbg:
3148     case LLVMContext::MD_tbaa:
3149     case LLVMContext::MD_prof:
3150     case LLVMContext::MD_fpmath:
3151     case LLVMContext::MD_tbaa_struct:
3152     case LLVMContext::MD_invariant_load:
3153     case LLVMContext::MD_alias_scope:
3154     case LLVMContext::MD_noalias:
3155     case LLVMContext::MD_nontemporal:
3156     case LLVMContext::MD_mem_cache_hint:
3157     case LLVMContext::MD_mem_parallel_loop_access:
3158     case LLVMContext::MD_access_group:
3159     case LLVMContext::MD_noundef:
3160     case LLVMContext::MD_noalias_addrspace:
3161       // All of these directly apply.
3162       Dest.setMetadata(ID, N);
3163       break;
3164 
3165     case LLVMContext::MD_nonnull:
3166       copyNonnullMetadata(Source, N, Dest);
3167       break;
3168 
3169     case LLVMContext::MD_align:
3170     case LLVMContext::MD_dereferenceable:
3171     case LLVMContext::MD_dereferenceable_or_null:
3172       // These only directly apply if the new type is also a pointer.
3173       if (NewType->isPointerTy())
3174         Dest.setMetadata(ID, N);
3175       break;
3176 
3177     case LLVMContext::MD_range:
3178       copyRangeMetadata(DL, Source, N, Dest);
3179       break;
3180 
3181     case LLVMContext::MD_nofpclass:
3182       // This only applies if the floating-point type interpretation. This
3183       // should handle degenerate cases like casting between a scalar and single
3184       // element vector.
3185       if (NewType->getScalarType() == Source.getType()->getScalarType())
3186         Dest.setMetadata(ID, N);
3187       break;
3188     }
3189   }
3190 }
