3192 void llvm::patchReplacementInstruction(Instruction *I, Value *Repl) {
3193   auto *ReplInst = dyn_cast<Instruction>(Repl);
3194   if (!ReplInst)
3195     return;
3196 
3197   // Patch the replacement so that it is not more restrictive than the value
3198   // being replaced.
3199   WithOverflowInst *UnusedWO;
3200   // When replacing the result of a llvm.*.with.overflow intrinsic with a
3201   // overflowing binary operator, nuw/nsw flags may no longer hold.
3202   if (isa<OverflowingBinaryOperator>(ReplInst) &&
3203       match(I, m_ExtractValue<0>(m_WithOverflowInst(UnusedWO))))
3204     ReplInst->dropPoisonGeneratingFlags();
3205   // Note that if 'I' is a load being replaced by some operation,
3206   // for example, by an arithmetic operation, then andIRFlags()
3207   // would just erase all math flags from the original arithmetic
3208   // operation, which is clearly not wanted and not needed.
3209   else if (!isa<LoadInst>(I))
3210     ReplInst->andIRFlags(I);
3211 
3212   // Handle attributes.
3213   if (auto *CB1 = dyn_cast<CallBase>(ReplInst)) {
3214     if (auto *CB2 = dyn_cast<CallBase>(I)) {
3215       bool Success = CB1->tryIntersectAttributes(CB2);
3216       assert(Success && "We should not be trying to sink callbases "
3217                         "with non-intersectable attributes");
3218       // For NDEBUG Compile.
3219       (void)Success;
3220     }
3221   }
3222 
3223   // FIXME: If both the original and replacement value are part of the
3224   // same control-flow region (meaning that the execution of one
3225   // guarantees the execution of the other), then we can combine the
3226   // noalias scopes here and do better than the general conservative
3227   // answer used in combineMetadata().
3228 
3229   // In general, GVN unifies expressions over different control-flow
3230   // regions, and so we need a conservative combination of the noalias
3231   // scopes.
3232   combineMetadataForCSE(ReplInst, I, false);
3233 }
