572 void Instruction::dropUBImplyingAttrsAndMetadata(ArrayRef<unsigned> Keep) {
573   // !annotation and !prof metadata does not impact semantics.
574   // !range, !nonnull and !align produce poison, so they are safe to speculate.
575   // !fpmath specifies floating-point precision and does not imply UB.
576   // !mem.cache_hint is a performance hint and does not imply UB.
577   // !noundef and various AA metadata must be dropped, as it generally produces
578   // immediate undefined behavior.
579   static const unsigned KnownIDs[] = {
580       LLVMContext::MD_annotation,    LLVMContext::MD_range,
581       LLVMContext::MD_nonnull,       LLVMContext::MD_align,
582       LLVMContext::MD_fpmath,        LLVMContext::MD_prof,
583       LLVMContext::MD_mem_cache_hint};
584   SmallVector<unsigned> KeepIDs;
585   KeepIDs.reserve(Keep.size() + std::size(KnownIDs));
586   append_range(KeepIDs, (!ProfcheckDisableMetadataFixes ? KnownIDs
587                                                         : drop_end(KnownIDs)));
588   append_range(KeepIDs, Keep);
589   dropUBImplyingAttrsAndUnknownMetadata(KeepIDs);
590 }
