592 bool Instruction::hasUBImplyingAttrs() const {
593   auto *CB = dyn_cast<CallBase>(this);
594   if (!CB)
595     return false;
596   // For call instructions, we also need to check parameter and return
597   // attributes that can cause UB.
598   for (unsigned ArgNo = 0; ArgNo < CB->arg_size(); ArgNo++)
599     if (CB->isPassingUndefUB(ArgNo))
600       return true;
601   return CB->hasRetAttr(Attribute::NoUndef) ||
602          CB->hasRetAttr(Attribute::Dereferenceable) ||
603          CB->hasRetAttr(Attribute::DereferenceableOrNull);
