709 void Instruction::copyIRFlags(const Value *V, bool IncludeWrapFlags) {
710   // Copy the wrapping flags.
711   if (IncludeWrapFlags && isa<OverflowingBinaryOperator>(this)) {
712     if (auto *OB = dyn_cast<OverflowingBinaryOperator>(V)) {
713       setHasNoSignedWrap(OB->hasNoSignedWrap());
714       setHasNoUnsignedWrap(OB->hasNoUnsignedWrap());
715     }
716   }
717 
718   if (auto *TI = dyn_cast<TruncInst>(V)) {
719     if (isa<TruncInst>(this)) {
720       setHasNoSignedWrap(TI->hasNoSignedWrap());
721       setHasNoUnsignedWrap(TI->hasNoUnsignedWrap());
722     }
723   }
724 
725   // Copy the exact flag.
726   if (auto *PE = dyn_cast<PossiblyExactOperator>(V))
727     if (isa<PossiblyExactOperator>(this))
728       setIsExact(PE->isExact());
729 
730   if (auto *SrcPD = dyn_cast<PossiblyDisjointInst>(V))
731     if (auto *DestPD = dyn_cast<PossiblyDisjointInst>(this))
732       DestPD->setIsDisjoint(SrcPD->isDisjoint());
733 
734   // Copy the fast-math flags.
735   if (auto *FP = dyn_cast<FPMathOperator>(V))
736     if (isa<FPMathOperator>(this))
737       copyFastMathFlags(FP->getFastMathFlags());
738 
739   if (auto *SrcGEP = dyn_cast<GetElementPtrInst>(V))
740     if (auto *DestGEP = dyn_cast<GetElementPtrInst>(this))
741       DestGEP->setNoWrapFlags(SrcGEP->getNoWrapFlags() |
742                               DestGEP->getNoWrapFlags());
743 
744   if (auto *NNI = dyn_cast<PossiblyNonNegInst>(V))
745     if (isa<PossiblyNonNegInst>(this))
746       setNonNeg(NNI->hasNonNeg());
747 
748   if (auto *SrcICmp = dyn_cast<ICmpInst>(V))
749     if (auto *DestICmp = dyn_cast<ICmpInst>(this))
750       DestICmp->setSameSign(SrcICmp->hasSameSign());
751 }
