753 void Instruction::andIRFlags(const Value *V) {
754   if (auto *OB = dyn_cast<OverflowingBinaryOperator>(V)) {
755     if (isa<OverflowingBinaryOperator>(this)) {
756       setHasNoSignedWrap(hasNoSignedWrap() && OB->hasNoSignedWrap());
757       setHasNoUnsignedWrap(hasNoUnsignedWrap() && OB->hasNoUnsignedWrap());
758     }
759   }
760 
761   if (auto *TI = dyn_cast<TruncInst>(V)) {
762     if (isa<TruncInst>(this)) {
763       setHasNoSignedWrap(hasNoSignedWrap() && TI->hasNoSignedWrap());
764       setHasNoUnsignedWrap(hasNoUnsignedWrap() && TI->hasNoUnsignedWrap());
765     }
766   }
767 
768   if (auto *PE = dyn_cast<PossiblyExactOperator>(V))
769     if (isa<PossiblyExactOperator>(this))
770       setIsExact(isExact() && PE->isExact());
771 
772   if (auto *SrcPD = dyn_cast<PossiblyDisjointInst>(V))
773     if (auto *DestPD = dyn_cast<PossiblyDisjointInst>(this))
774       DestPD->setIsDisjoint(DestPD->isDisjoint() && SrcPD->isDisjoint());
775 
776   if (auto *FP = dyn_cast<FPMathOperator>(V)) {
777     if (isa<FPMathOperator>(this)) {
778       FastMathFlags FM = getFastMathFlags();
779       FM &= FP->getFastMathFlags();
780       copyFastMathFlags(FM);
781     }
782   }
783 
784   if (auto *SrcGEP = dyn_cast<GetElementPtrInst>(V))
785     if (auto *DestGEP = dyn_cast<GetElementPtrInst>(this))
786       DestGEP->setNoWrapFlags(SrcGEP->getNoWrapFlags() &
