788 
789   if (auto *NNI = dyn_cast<PossiblyNonNegInst>(V))
790     if (isa<PossiblyNonNegInst>(this))
791       setNonNeg(hasNonNeg() && NNI->hasNonNeg());
792 
793   if (auto *SrcICmp = dyn_cast<ICmpInst>(V))
