5580 void Verifier::visitMemCacheHintMetadata(Instruction &I, MDNode *MD) {
5581   Check(I.mayReadOrWriteMemory(),
5582         "!mem.cache_hint is only valid on memory operations", &I);
5583 
5584   Check(MD->getNumOperands() % 2 == 0,
5585         "!mem.cache_hint must have even number of operands "
5586         "(operand_no, hint_node pairs)",
5587         MD);
5588 
5589   auto IsMemoryObjectOperand = [](const Value *V) {
5590     return V->getType()->isPtrOrPtrVectorTy();
5591   };
5592 
5593   unsigned NumMemoryObjectOperands = 0;
5594   if (const auto *CB = dyn_cast<CallBase>(&I))
5595     NumMemoryObjectOperands = count_if(CB->args(), [&](const Use &Arg) {
5596       return IsMemoryObjectOperand(Arg.get());
5597     });
5598   else
5599     NumMemoryObjectOperands = count_if(I.operands(), [&](const Use &Op) {
5600       return IsMemoryObjectOperand(Op.get());
5601     });
5602 
5603   SmallVector<unsigned, 4> SeenOperandNos;
5604 
5605   // Top-level metadata alternates: i32 operand_no, MDNode hint_node.
5606   for (unsigned i = 0; i + 1 < MD->getNumOperands(); i += 2) {
5607     auto *OpNoCI = mdconst::dyn_extract<ConstantInt>(MD->getOperand(i));
5608     Check(OpNoCI,
5609           "!mem.cache_hint operand_no must be an integer constant in pair", MD);
5610 
5611     Check(OpNoCI->getValue().isNonNegative(),
5612           "!mem.cache_hint operand_no must be non-negative", MD);
5613 
5614     uint64_t OperandNo = OpNoCI->getZExtValue();
5615     Check(OperandNo < NumMemoryObjectOperands,
5616           "!mem.cache_hint operand_no must refer to a valid memory object "
5617           "operand",
5618           &I);
5619 
5620     Check(!is_contained(SeenOperandNos, OperandNo),
5621           "!mem.cache_hint contains duplicate operand_no", MD);
5622     SeenOperandNos.push_back(OperandNo);
5623 
5624     const auto *Node = dyn_cast<MDNode>(MD->getOperand(i + 1));
5625     Check(Node, "!mem.cache_hint hint node must be a metadata node", MD);
5626 
5627     Check(Node->getNumOperands() % 2 == 0,
5628           "!mem.cache_hint hint node must have even number of operands "
5629           "(key-value pairs)",
5630           Node);
5631 
5632     SmallVector<StringRef, 8> SeenKeys;
5633     for (unsigned j = 0; j + 1 < Node->getNumOperands(); j += 2) {
5634       const auto *Key = dyn_cast<MDString>(Node->getOperand(j));
5635       Check(Key, "!mem.cache_hint key must be a string", Node);
5636 
5637       StringRef KeyStr = Key->getString();
5638       Check(!is_contained(SeenKeys, KeyStr),
5639             "!mem.cache_hint hint node contains duplicate key", Node);
5640       SeenKeys.push_back(KeyStr);
5641       // Values are target-specific and not validated here.
5642     }
5643   }
5644 }
