5648 void Verifier::visitInstruction(Instruction &I) {
5649   BasicBlock *BB = I.getParent();
5650   Check(BB, "Instruction not embedded in basic block!", &I);
5651 
5652   if (!isa<PHINode>(I)) {   // Check that non-phi nodes are not self referential
5653     for (User *U : I.users()) {
5654       Check(U != (User *)&I || !DT.isReachableFromEntry(BB),
5655             "Only PHI nodes may reference their own value!", &I);
5656     }
5657   }
5658 
5659   // Check that void typed values don't have names
5660   Check(!I.getType()->isVoidTy() || !I.hasName(),
5661         "Instruction has a name, but provides a void value!", &I);
5662 
5663   // Check that the return value of the instruction is either void or a legal
5664   // value type.
5665   Check(I.getType()->isVoidTy() || I.getType()->isFirstClassType(),
5666         "Instruction returns a non-scalar type!", &I);
5667 
5668   // Check that the instruction doesn't produce metadata. Calls are already
5669   // checked against the callee type.
5670   Check(!I.getType()->isMetadataTy() || isa<CallInst>(I) || isa<InvokeInst>(I),
5671         "Invalid use of metadata!", &I);
