5677     if (Instruction *Used = dyn_cast<Instruction>(U.getUser()))
5678       Check(Used->getParent() != nullptr,
5679             "Instruction referencing"
5680             " instruction not embedded in a basic block!",
5681             &I, Used);
5682     else {
5683       CheckFailed("Use of instruction is not an instruction!", U);
5684       return;
5685     }
5686   }
5687 
5688   // Get a pointer to the call base of the instruction if it is some form of
5689   // call.
5690   const CallBase *CBI = dyn_cast<CallBase>(&I);
5691 
5692   for (unsigned i = 0, e = I.getNumOperands(); i != e; ++i) {
5693     Check(I.getOperand(i) != nullptr, "Instruction has null operand!", &I);
5694 
5695     // Check to make sure that only first-class-values are operands to
5696     // instructions.
5697     if (!I.getOperand(i)->getType()->isFirstClassType()) {
5698       Check(false, "Instruction operands must be first-class values!", &I);
5699     }
5700 
5701     if (Function *F = dyn_cast<Function>(I.getOperand(i))) {
