711     }
712 
713     if (auto *CastUser = dyn_cast<CastInst>(Load.user_back())) {
714       Type *DestTy = CastUser->getDestTy();
715       if (CastUser->isNoopCast(IC.getDataLayout()) &&
716           LoadTy->isPtrOrPtrVectorTy() == DestTy->isPtrOrPtrVectorTy() &&
